def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            continue
        score = 0
        for j in range(1, 8):
            factor = j * utilization
            if factor < 0.3:
                score += np.exp(-factor) + np.sin(factor * np.pi)
            elif 0.3 <= factor <= 0.7:
                score += np.log(factor + 1) * (1 + factor)
            elif 0.7 < factor <= 1:
                score += factor ** 3 - factor * 0.5
            else:
                score += factor ** 2 + np.tanh(factor)
            if j % 2 == 0:
                score *= 1.1
            else:
                score *= 0.9
        if bin_capacity < item * 1.5:
            score *= 1.8
            if score > 10:
                score -= 3
        elif item * 1.5 <= bin_capacity <= item * 3:
            for k in range(3):
                score += np.sqrt(bin_capacity / (item + k + 1))
            if score > 20:
                score /= 2
        else:
            temp = 1
            for m in range(1, 5):
                temp *= (bin_capacity / (item * m + 1)) ** 0.5
            score *= temp
            if score < 0:
                score = abs(score) + 5
        priorities[i] = score
    return priorities
